import { NextResponse } from "next/server"
import { calculateRealTimeRisk } from "@/lib/risk-model"
import type { CableSegment, SpaceWeather } from "@/lib/types"

export async function POST(req: Request) {
  try {
    // In a real app, we might fetch cables from DB or cache here.
    // For this demo, we'll fetch from our own internal API or reuse logic.
    // To keep it self-contained, we'll re-fetch the mock cables internally.

    // 1. Get Cables (Internal call logic)
    const cablesRes = await fetch(new URL("/api/cables", req.url))
    const cables: CableSegment[] = await cablesRes.json()

    // 2. Get Weather (Internal call logic)
    const weatherRes = await fetch(new URL("/api/space-weather/realtime", req.url))
    const weather: SpaceWeather = await weatherRes.json()

    // 3. Calculate Risk
    const segmentRisks = calculateRealTimeRisk(cables, weather)

    // 4. Aggregate
    const cableAggregates = segmentRisks
      .map((r) => ({
        cableId: r.cableId,
        cableName: r.cableName,
        maxRisk: r.riskScore,
        meanRisk: r.riskScore,
        worstSegment: { lat: r.meanLat, lon: r.meanLon, riskScore: r.riskScore },
      }))
      .sort((a, b) => b.maxRisk - a.maxRisk)

    return NextResponse.json({
      updatedAt: new Date().toISOString(),
      globalKp: weather.kp.current,
      gScale: weather.kp.scale,
      segmentRisks,
      cableAggregates,
    })
  } catch (error) {
    console.error(error)
    return NextResponse.json({ error: "Calculation failed" }, { status: 500 })
  }
}
